WHERE NOT EXISTS (
  SELECT 1 FROM public.universities existing
  WHERE existing.source <> 'hipo'
    AND existing.email_domains && v.email_domains
)
ON CONFLICT (source, external_ref) DO UPDATE
  SET name = EXCLUDED.name, country = EXCLUDED.country,
      email_domains = EXCLUDED.email_domains,
      last_scraped_at = now(), updated_at = now();
